29: namespace Envoy {
30: namespace Extensions {
31: namespace HttpFilters {
32: namespace ExtAuthz {
33: 
34: /**
35:  * All stats for the Ext Authz filter. @see stats_macros.h
36:  */
37: 
38: #define ALL_EXT_AUTHZ_FILTER_STATS(COUNTER)                                                        \
39:   COUNTER(ok)                                                                                      \
40:   COUNTER(denied)                                                                                  \
41:   COUNTER(error)                                                                                   \
42:   COUNTER(disabled)                                                                                \
43:   COUNTER(failure_mode_allowed)                                                                    \
44:   COUNTER(invalid)                                                                                 \
45:   COUNTER(ignored_dynamic_metadata)
46: 
47: /**
48:  * Wrapper struct for ext_authz filter stats. @see stats_macros.h
49:  */
50: struct ExtAuthzFilterStats {
51:   ALL_EXT_AUTHZ_FILTER_STATS(GENERATE_COUNTER_STRUCT)
52: };
53: 
54: /**
55:  * Configuration for the External Authorization (ext_authz) filter.
56:  */
57: class FilterConfig {
58:   using LabelsMap = Protobuf::Map<std::string, std::string>;
59: 
60: public:
61:   FilterConfig(const envoy::extensions::filters::http::ext_authz::v3::ExtAuthz& config,
62:                Stats::Scope& scope, const std::string& stats_prefix,
63:                Server::Configuration::ServerFactoryContext& factory_context);
64: 
65:   bool allowPartialMessage() const { return allow_partial_message_; }
66: 
67:   bool withRequestBody() const { return max_request_bytes_ > 0; }
68: 
69:   bool failureModeAllow() const { return failure_mode_allow_; }
70: 
71:   bool failureModeAllowHeaderAdd() const { return failure_mode_allow_header_add_; }
72: 
73:   bool clearRouteCache() const { return clear_route_cache_; }
74: 
75:   uint32_t maxRequestBytes() const { return max_request_bytes_; }
76: 
77:   bool packAsBytes() const { return pack_as_bytes_; }
78: 
79:   bool headersAsBytes() const { return encode_raw_headers_; }
80: 
81:   Filters::Common::MutationRules::CheckResult
82:   checkDecoderHeaderMutation(const Filters::Common::MutationRules::CheckOperation& operation,
83:                              const Http::LowerCaseString& key, absl::string_view value) const {
84:     if (!decoder_header_mutation_checker_.has_value()) {
85:       return Filters::Common::MutationRules::CheckResult::OK;
86:     }
87:     return decoder_header_mutation_checker_->check(operation, key, value);
88:   }
89: 
90:   // Used for headers_to_remove to avoid a redundant pseudo header check.
91:   bool hasDecoderHeaderMutationRules() const {
92:     return decoder_header_mutation_checker_.has_value();
93:   }
94: 
95:   bool enableDynamicMetadataIngestion() const { return enable_dynamic_metadata_ingestion_; }
96: 
97:   Http::Code statusOnError() const { return status_on_error_; }
98: 
99:   bool validateMutations() const { return validate_mutations_; }
100: 
101:   bool filterEnabled(const envoy::config::core::v3::Metadata& metadata) {
102:     const bool enabled = filter_enabled_.has_value() ? filter_enabled_->enabled() : true;
103:     const bool enabled_metadata =
104:         filter_enabled_metadata_.has_value() ? filter_enabled_metadata_->match(metadata) : true;
105:     return enabled && enabled_metadata;
106:   }
107: 
108:   bool denyAtDisable() {
109:     return deny_at_disable_.has_value() ? deny_at_disable_->enabled() : false;
110:   }
111: 
112:   Stats::Scope& scope() { return scope_; }
113: 
114:   Http::Context& httpContext() { return http_context_; }
115: 
116:   const std::vector<std::string>& metadataContextNamespaces() {
117:     return metadata_context_namespaces_;
118:   }
119: 
120:   const std::vector<std::string>& typedMetadataContextNamespaces() {
121:     return typed_metadata_context_namespaces_;
122:   }
123: 
124:   const std::vector<std::string>& routeMetadataContextNamespaces() {
125:     return route_metadata_context_namespaces_;
126:   }
127: 
128:   const std::vector<std::string>& routeTypedMetadataContextNamespaces() {
129:     return route_typed_metadata_context_namespaces_;
130:   }
131: 
132:   const ExtAuthzFilterStats& stats() const { return stats_; }
133: 
134:   void incCounter(Stats::Scope& scope, Stats::StatName name) {
135:     scope.counterFromStatName(name).inc();
136:   }
137: 
138:   bool includePeerCertificate() const { return include_peer_certificate_; }
139:   bool includeTLSSession() const { return include_tls_session_; }
140:   const LabelsMap& destinationLabels() const { return destination_labels_; }
141: 
142:   bool chargeClusterResponseStats() const { return charge_cluster_response_stats_; }
143: 
144:   const Filters::Common::ExtAuthz::MatcherSharedPtr& allowedHeadersMatcher() const {
145:     return allowed_headers_matcher_;
146:   }
147: 
148:   const Filters::Common::ExtAuthz::MatcherSharedPtr& disallowedHeadersMatcher() const {
149:     return disallowed_headers_matcher_;
150:   }
151: 
152: private:
153:   static Http::Code toErrorCode(uint64_t status) {
154:     const auto code = static_cast<Http::Code>(status);
155:     if (code >= Http::Code::Continue && code <= Http::Code::NetworkAuthenticationRequired) {
156:       return code;
157:     }
158:     return Http::Code::Forbidden;
159:   }
160: 
