84:                     Filters::Common::MutationRules::Checker(config.decoder_header_mutation_rules(),
85:                                                             factory_context.regexEngine()))
86:               : absl::nullopt),
87:       enable_dynamic_metadata_ingestion_(
88:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, enable_dynamic_metadata_ingestion, true)),
89:       runtime_(factory_context.runtime()), http_context_(factory_context.httpContext()),
90:       filter_enabled_(config.has_filter_enabled()
91:                           ? absl::optional<Runtime::FractionalPercent>(
92:                                 Runtime::FractionalPercent(config.filter_enabled(), runtime_))
93:                           : absl::nullopt),
94:       filter_enabled_metadata_(
95:           config.has_filter_enabled_metadata()
96:               ? absl::optional<Matchers::MetadataMatcher>(
97:                     Matchers::MetadataMatcher(config.filter_enabled_metadata(), factory_context))
98:               : absl::nullopt),
99:       deny_at_disable_(config.has_deny_at_disable()
100:                            ? absl::optional<Runtime::FeatureFlag>(
101:                                  Runtime::FeatureFlag(config.deny_at_disable(), runtime_))
102:                            : absl::nullopt),
103:       pool_(scope_.symbolTable()),
104:       metadata_context_namespaces_(config.metadata_context_namespaces().begin(),
105:                                    config.metadata_context_namespaces().end()),
106:       typed_metadata_context_namespaces_(config.typed_metadata_context_namespaces().begin(),
107:                                          config.typed_metadata_context_namespaces().end()),
108:       route_metadata_context_namespaces_(config.route_metadata_context_namespaces().begin(),
109:                                          config.route_metadata_context_namespaces().end()),
110:       route_typed_metadata_context_namespaces_(
111:           config.route_typed_metadata_context_namespaces().begin(),
112:           config.route_typed_metadata_context_namespaces().end()),
113:       include_peer_certificate_(config.include_peer_certificate()),
114:       include_tls_session_(config.include_tls_session()),
115:       charge_cluster_response_stats_(
116:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, charge_cluster_response_stats, true)),
117:       stats_(generateStats(stats_prefix, config.stat_prefix(), scope)),
118:       ext_authz_ok_(pool_.add(createPoolStatName(config.stat_prefix(), "ok"))),
119:       ext_authz_denied_(pool_.add(createPoolStatName(config.stat_prefix(), "denied"))),
120:       ext_authz_error_(pool_.add(createPoolStatName(config.stat_prefix(), "error"))),
121:       ext_authz_invalid_(pool_.add(createPoolStatName(config.stat_prefix(), "invalid"))),
122:       ext_authz_failure_mode_allowed_(
123:           pool_.add(createPoolStatName(config.stat_prefix(), "failure_mode_allowed"))) {
124:   auto bootstrap = factory_context.bootstrap();
125:   auto labels_key_it =
126:       bootstrap.node().metadata().fields().find(config.bootstrap_metadata_labels_key());
127:   if (labels_key_it != bootstrap.node().metadata().fields().end()) {
128:     for (const auto& labels_it : labels_key_it->second.struct_value().fields()) {
129:       destination_labels_[labels_it.first] = labels_it.second.string_value();
