73: ExtAuthzFilterConfig::createRouteSpecificFilterConfigTyped(
74:     const envoy::extensions::filters::http::ext_authz::v3::ExtAuthzPerRoute& proto_config,
75:     Server::Configuration::ServerFactoryContext&, ProtobufMessage::ValidationVisitor&) {
76:   return std::make_shared<FilterConfigPerRoute>(proto_config);
