78: using UnsafeHeader = std::pair<std::string, std::string>;
79: using UnsafeHeaderVector = std::vector<UnsafeHeader>;
80: /**
81:  * Authorization response object for a RequestCallback.
82:  *
83:  * Header mutations and query parameter mutations are not expected to already be validated by the
84:  * client before packing them into this struct (hence they are "unsafe").
85:  */
86: struct Response {
87:   // Call status.
88:   CheckStatus status;
89:   // A set of HTTP headers returned by the authorization server, that will be optionally appended
90:   // to the request to the upstream server.
91:   UnsafeHeaderVector headers_to_append;
92:   // A set of HTTP headers returned by the authorization server, will be optionally set
93:   // (using "setCopy") to the request to the upstream server.
94:   UnsafeHeaderVector headers_to_set;
95:   // A set of HTTP headers returned by the authorization server, will be optionally added
96:   // (using "addCopy") to the request to the upstream server.
97:   UnsafeHeaderVector headers_to_add;
98:   // A set of HTTP headers returned by the authorization server, will be optionally added
99:   // (using "addCopy") to the response sent back to the downstream client on OK auth
100:   // responses.
101:   UnsafeHeaderVector response_headers_to_add;
102:   // A set of HTTP headers returned by the authorization server, will be optionally set (using
103:   // "setCopy") to the response sent back to the downstream client on OK auth responses.
104:   UnsafeHeaderVector response_headers_to_set;
105:   // A set of HTTP headers returned by the authorization server, will be optionally added
106:   // (using "addCopy") to the response sent back to the downstream client on OK auth
107:   // responses only if the headers were not returned from the authz server.
108:   UnsafeHeaderVector response_headers_to_add_if_absent;
109:   // A set of HTTP headers returned by the authorization server, will be optionally set (using
110:   // "setCopy") to the response sent back to the downstream client on OK auth responses
111:   // only if the headers were returned from the authz server.
112:   UnsafeHeaderVector response_headers_to_overwrite_if_exists;
113:   // A set of HTTP headers consumed by the authorization server, will be removed
114:   // from the request to the upstream server.
115:   std::vector<std::string> headers_to_remove;
116:   // A set of query string parameters to be set (possibly overwritten) on the
117:   // request to the upstream server.
118:   Http::Utility::QueryParamsVector query_parameters_to_set;
119:   // A set of query string parameters to remove from the request to the upstream server.
120:   std::vector<std::string> query_parameters_to_remove;
121:   // Optional http body used only on denied response.
122:   std::string body;
123:   // Optional http status used only on denied response.
124:   Http::Code status_code{};
125: 
126:   // A set of metadata returned by the authorization server, that will be emitted as filter's
127:   // dynamic metadata that other filters can leverage.
128:   ProtobufWkt::Struct dynamic_metadata;
