27: // Static header map used for creating authorization requests.
28: const Http::HeaderMap& lengthZeroHeader() {
29:   static const auto headers = Http::createHeaderMap<Http::RequestHeaderMapImpl>(
30:       {{Http::Headers::get().ContentLength, std::to_string(0)}});
31:   return *headers;
32: }
