34: // Static response used for creating authorization ERROR responses.
35: const Response& errorResponse() {
36:   CONSTRUCT_ON_FIRST_USE(Response, Response{CheckStatus::Error,
37:                                             UnsafeHeaderVector{},
38:                                             UnsafeHeaderVector{},
39:                                             UnsafeHeaderVector{},
40:                                             UnsafeHeaderVector{},
41:                                             UnsafeHeaderVector{},
42:                                             UnsafeHeaderVector{},
43:                                             UnsafeHeaderVector{},
44:                                             {{}},
45:                                             Http::Utility::QueryParamsVector{},
46:                                             {},
47:                                             EMPTY_STRING,
48:                                             Http::Code::Forbidden,
49:                                             ProtobufWkt::Struct{}});
50: }
